const fs = global.get('fs');
const userDir = global.get('userDir') || '/data';
const credsPath = userDir + '/clusterra-creds.json';
let creds;
try { creds = JSON.parse(fs.readFileSync(credsPath, 'utf8')); }
catch (e) { node.error('cannot read clusterra-creds.json: ' + e.message, msg); return null; }

const method = (msg.method || 'GET').toUpperCase();
let path = msg.path || '';
if (!path) { node.error('msg.path is required', msg); return null; }

const params = msg.params || msg;
path = path.replace(/\{([^}]+)\}/g, (_m, key) => {
    if (key === 'cluster_id') return creds.cluster_id;
    const v = params[key];
    if (v === undefined || v === null) {
        node.error('missing path param ' + key, msg);
        throw new Error('missing param ' + key);
    }
    return encodeURIComponent(String(v));
});

msg.url = creds.api_url + path;
msg.method = method;
msg.headers = {
    'Authorization': 'Bearer ' + creds.auth_token,
    'Accept': msg.stream ? 'text/event-stream' : 'application/json'
};
if (msg.body !== undefined && (method === 'POST' || method === 'PUT' || method === 'PATCH')) {
    msg.headers['Content-Type'] = 'application/json';
    msg.payload = msg.body;
} else {
    msg.payload = undefined;
}
return msg;

// Open the SSE connection inline — Node-RED's http-request node has no
// streaming mode, so we use the http(s) module directly and emit one msg
// per event line.
const urlMod = global.get('url') || require('url');
const u = new urlMod.URL(msg.url);
const lib = u.protocol === 'https:' ? (global.get('https') || require('https')) : (global.get('http') || require('http'));
const opts = {
    method: msg.method || 'GET',
    hostname: u.hostname,
    port: u.port || (u.protocol === 'https:' ? 443 : 80),
    path: u.pathname + u.search,
    headers: msg.headers || {}
};
const ctxKey = 'sse_' + msg._msgid;
const req = lib.request(opts, (res) => {
    if (res.statusCode >= 400) {
        node.error('SSE ' + res.statusCode + ' ' + res.statusMessage, msg);
        return;
    }
    let buf = '';
    res.setEncoding('utf8');
    res.on('data', (chunk) => {
        buf += chunk;
        let idx;
        while ((idx = buf.indexOf('\n\n')) >= 0) {
            const block = buf.slice(0, idx);
            buf = buf.slice(idx + 2);
            const out = { _msgid: RED.util.generateId() };
            for (const line of block.split('\n')) {
                const c = line.indexOf(':');
                if (c < 0) continue;
                const k = line.slice(0, c).trim();
                const v = line.slice(c + 1).trim();
                if (k === 'data') {
                    try { out.payload = JSON.parse(v); } catch { out.payload = v; }
                } else if (k === 'event') {
                    out.topic = v;
                }
            }
            if (out.payload !== undefined) node.send(out);
        }
    });
    res.on('end', () => { node.status({ fill: 'grey', text: 'closed' }); });
});
req.on('error', (e) => node.error('SSE error: ' + e.message, msg));
req.end();
node.status({ fill: 'green', text: 'streaming' });
return null;
